import{c as t,cG as a,cb as r,c8 as e,cf as l,cT as i,ce as n}from"./chunks/framework.BlkIsu1j.js";const s=JSON.parse('{"title":"【RISC-V 汇编】从零开始的 RISC-V 汇编之旅","description":"","frontmatter":{"title":"【RISC-V 汇编】从零开始的 RISC-V 汇编之旅","layout":"doc","categories":"Assembly","tags":["RISC-V","Assembly"],"prev":false,"next":{"text":"第1章 为什么要学 RISC-V 汇编","link":"/lang/assembly/01_why_riscv"},"comments":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/index.md","filePath":"lang/assembly/index.md","lastUpdated":1780199429000}'),d={id:"frontmatter-title",tabindex:"-1"};const o=t({name:"lang/assembly/index.md"},[["render",function(t,s,o,h,c,m){return a(),r("div",null,[e("h1",d,[l(i(t.$frontmatter.title)+" ",1),s[0]||(s[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),s[1]||(s[1]=n('<h2 id="risc-v-是什么" tabindex="-1">RISC-V 是什么 <a class="header-anchor" href="#risc-v-是什么" aria-label="Permalink to “RISC-V 是什么”">​</a></h2><ul><li>RISC-V 是一款开源、免版税的指令集架构（ISA），2010 年由 UC Berkeley 发布</li><li>模块化设计：基础整数 ISA（RV32I/RV64I）+ 可选标准扩展（M/A/F/D/C 等）</li><li>与 x86（CISC，闭源，&gt;1500 条指令）和 ARM（RISC，需授权费）的本质区别</li><li>RV64I 仅约 50 条基础指令，编码规整，学习成本远低于 x86</li></ul><h2 id="为什么要学-risc-v-汇编" tabindex="-1">为什么要学 RISC-V 汇编 <a class="header-anchor" href="#为什么要学-risc-v-汇编" aria-label="Permalink to “为什么要学 RISC-V 汇编”">​</a></h2><ul><li><strong>理解底层</strong>：寄存器、内存、指令执行周期——所有程序最终都运行在这些之上</li><li><strong>调试与逆向</strong>：gdb 反汇编、性能热点分析、理解编译器优化</li><li><strong>系统编程</strong>：bootloader、OS 内核、嵌入式开发都需要汇编</li><li><strong>生态爆发</strong>：从 IoT 到服务器，Linux 内核已原生支持 RISC-V</li></ul><h2 id="教程全览-22-章覆盖-risc-v-汇编体系" tabindex="-1">教程全览：22 章覆盖 RISC-V 汇编体系 <a class="header-anchor" href="#教程全览-22-章覆盖-risc-v-汇编体系" aria-label="Permalink to “教程全览：22 章覆盖 RISC-V 汇编体系”">​</a></h2><table tabindex="0"><thead><tr><th>篇章</th><th>章节</th><th>主题</th></tr></thead><tbody><tr><td>第一篇：基础篇</td><td>1-4</td><td>RISC-V 历史、数制、体系结构、第一个程序</td></tr><tr><td>第二篇：指令篇</td><td>5-9</td><td>算术逻辑、立即数移位、访存、分支跳转、伪指令</td></tr><tr><td>第三篇：系统篇</td><td>10-13</td><td>栈与内存、调用约定、系统调用、汇编器与ELF</td></tr><tr><td>第四篇：扩展篇</td><td>14-17</td><td>M乘除、A原子、F/D浮点、C压缩指令</td></tr><tr><td>第五篇：实战篇</td><td>18-19</td><td>C 互操作、交互式计算器</td></tr><tr><td>第六篇：特权架构篇</td><td>20-22</td><td>特权级别与CSR、异常与中断、虚拟内存</td></tr></tbody></table><h2 id="工具与环境" tabindex="-1">工具与环境 <a class="header-anchor" href="#工具与环境" aria-label="Permalink to “工具与环境”">​</a></h2><ul><li><strong>前期（第1-12章）</strong>：使用 <a href="https://riscv-programming.org/ale/" target="_blank" rel="noreferrer">RISC-V ALE</a> 在线环境，浏览器打开即用，零安装</li><li><strong>后期（第13章起）</strong>：GNU RISC-V Toolchain + QEMU 模拟器 <ul><li>macOS: <code>brew install riscv64-elf-gcc riscv64-elf-binutils qemu</code></li><li>Ubuntu: <code>apt install gcc-riscv64-linux-gnu binutils-riscv64-linux-gnu qemu-user-static</code></li></ul></li></ul><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to “前置知识”">​</a></h2><ul><li>至少一门高级语言（C/Python/Java/Go 均可）</li><li>基本命令行操作（cd、ls、运行命令）</li><li><strong>不需要任何汇编或硬件基础</strong>——本教程从零讲起</li></ul><h2 id="写作风格" tabindex="-1">写作风格 <a class="header-anchor" href="#写作风格" aria-label="Permalink to “写作风格”">​</a></h2><p>全书采用简洁总结式语言，精炼要点。每章末尾有要点总结，方便回顾。</p><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to “参考资源”">​</a></h2><ul><li><a href="https://riscv.org/specifications/ratified/" target="_blank" rel="noreferrer">RISC-V 官方规范</a></li><li><em>The RISC-V Reader: An Open Architecture Atlas</em> — Patterson &amp; Waterman</li><li><em>Computer Organization and Design: RISC-V Edition</em> — Patterson &amp; Hennessy</li><li><a href="https://riscv-programming.org/ale/" target="_blank" rel="noreferrer">RISC-V ALE 在线环境</a></li><li><a href="https://github.com/riscv/learn" target="_blank" rel="noreferrer">riscv/learn 社区资源</a></li></ul>',14))])}]]);export{s as __pageData,o as default};
